//export GitBlame
func GitBlame(commitHandle C.longlong, path *C.char, jsonOut **C.char) *C.char {
	commit, ok := loadHandle[*object.Commit](int64(commitHandle))
	if !ok {
		return C.CString("invalid commit handle")
	}
	result, err := git.Blame(commit, C.GoString(path))
	if err != nil {
		return toCError(err)
	}
	type lineJSON struct {
		Author      string `json:"author"`
		AuthorEmail string `json:"authorEmail"`
		Hash        string `json:"hash"`
		Date        int64  `json:"date"`
		Text        string `json:"text"`
	}
	type blameJSON struct {
		Path  string     `json:"path"`
		Rev   string     `json:"rev"`
		Lines []lineJSON `json:"lines"`
	}
	out := blameJSON{Path: result.Path, Rev: result.Rev.String()}
	for _, l := range result.Lines {
		out.Lines = append(out.Lines, lineJSON{
			Author:      l.AuthorName,
			AuthorEmail: l.Author,
			Hash:        l.Hash.String(),
			Date:        l.Date.Unix(),
			Text:        l.Text,
		})
	}
	data, err := json.Marshal(out)
	if err != nil {
		return toCError(err)
	}
	*jsonOut = C.CString(string(data))
	return nil
}

//export GitRepositoryStoreBlob
func GitRepositoryStoreBlob(rHandle C.longlong, dataBase64 *C.char, hashOut **C.char) *C.char {
	repo, ok := loadHandle[*git.Repository](int64(rHandle))
	if !ok {
		return C.CString("invalid repository handle")
	}
	content, err := base64.StdEncoding.DecodeString(C.GoString(dataBase64))
	if err != nil {
		return toCError(err)
	}
	obj := repo.Storer.NewEncodedObject()
	obj.SetType(plumbing.BlobObject)
	obj.SetSize(int64(len(content)))
	w, err := obj.Writer()
	if err != nil {
		return toCError(err)
	}
	if _, err = w.Write(content); err != nil {
		return toCError(err)
	}
	hash, err := repo.Storer.SetEncodedObject(obj)
	if err != nil {
		return toCError(err)
	}
	*hashOut = C.CString(hash.String())
	return nil
}

